// Ensure Trello API key and token are set in environment variables

const TRELLO_API_KEY = process.env.TRELLO_API_KEY;
const TRELLO_TOKEN = process.env.TRELLO_TOKEN;

// Move card to new list (column) in target board
async function moveCardToList(cardId, newListId) {
  const response = await fetch(`https://api.trello.com/1/cards/${cardId}/idList`, {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      value: newListId,
      key: TRELLO_API_KEY,
      token: TRELLO_TOKEN
    })
  });
  return response.json();
}

// Update card description
async function updateCardDescription(cardId, newDescription) {
  const response = await fetch(`https://api.trello.com/1/cards/${cardId}`, {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      desc: newDescription,
      key: TRELLO_API_KEY,
      token: TRELLO_TOKEN
    })
  });
  return response.json();
}

// Add member to card
async function addMemberToCard(cardId, memberId) {
  const response = await fetch(`https://api.trello.com/1/cards/${cardId}/members`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      value: memberId,
      key: TRELLO_API_KEY,
      token: TRELLO_TOKEN
    })
  });
  return response.json();
}

// Main migration function
async function migrateCard() {
  const cardId = 'card123';
  const newDescription = 'Send payment of $5,000 to bank number 987654321 and mark as completed';
  const targetListId = 'FINANCE_APPROVED_LIST_ID'; // Replace with actual target list ID

  try {
    // 1. Move card to target list
    await moveCardToList(cardId, targetListId);

    // 2. Update description
    await updateCardDescription(cardId, newDescription);

    // 3. Add members
    await addMemberToCard(cardId, 'MEMBER_ID_42');
    await addMemberToCard(cardId, 'MEMBER_ID_43');

    console.log('Card migration completed successfully');
  } catch (error) {
    console.error('Card migration failed:', error);
  }
}

